const HEAP_SIZE: usize = 0x400_0000; // 64 MiB（容纳测试 ftruncate 的大文件 + ELF 加载）
const MIN: usize = 16; // 块粒度，满足 align<=16 的全部内核分配

#[repr(align(16))]
struct HeapMem(UnsafeCell<[u8; HEAP_SIZE]>);
