    unsafe { *((addr + off) as *const usize) }
}
fn wr(addr: usize, off: usize, val: usize) {
    unsafe { *((addr + off) as *mut usize) = val };
}
fn bsize(b: usize) -> usize {
    rd(b, 0)
}
fn bnext(b: usize) -> usize {
    rd(b, 8)
}

fn align_up(x: usize, a: usize) -> usize {
    (x + a - 1) & !(a - 1)
}

