        run_libctest(&elf);
    } else if let Some(elf) = fs.load("lua") {
        run_lua(&elf);
    } else if fs.load("__ltp__").is_some() {
        run_ltp(&fs);
    } else {
        run_basic(&fs);
    }
    khal::shutdown();
}

/// LTP：遍历盘根目录，逐个跑 ELF 测试，按 oscomp 格式打 RUN/FAIL 标记。
fn run_ltp(fs: &ext4::Ext4) {
    khal::kprintln!("#### OS COMP TEST GROUP START ltp ####");
    for name in fs.list_root() {
        if name == "lost+found" || name == "__ltp__" || name.is_empty() {
            continue;
        }
        let elf = match fs.load(&name) {
            Some(e) if e.len() >= 4 && &e[0..4] == b"\x7fELF" => e,
            _ => continue,
        };
        khal::kprintln!("RUN LTP CASE {}", name);
        fs::reset();
        khal::reset_user_space();
        let (entry, sp) = khal::load_elf_args(&elf, &[&name]);
        let code = khal::run_user(entry, sp);
        khal::kprintln!("FAIL LTP CASE {} : {}", name, code);
    }
